// T620 CodeInjectionProcessor — version lock + pre-write audit + append-only
const INJECTION_LOCK_PREFIX = 'injection-version-lock' as const;
const INJECTION_AUDIT_PHASES = ['PRE_WRITE', 'COMPLETE', 'FAILED'] as const;

async injectCode(nodeId: string, version: string, code: string): Promise<DataProcessResult<Record<string, unknown>>> {
  const tenantId = this.tenantContext.getTenantId();
  const lockKey = `${INJECTION_LOCK_PREFIX}:${nodeId}:${version}`;

  // ORDER 1: version lock — SETNX
  const lockResult = await this.db.searchDocuments('injection-locks', { lockKey });
  if (lockResult.data?.length) {
    await this.queue.enqueue('InjectionConflict', { nodeId, version, tenantId, lockKey });
    return DataProcessResult.failure('INJECTION_CONFLICT', 'Version lock held — concurrent injection in progress');
  }
  await this.db.storeDocument('injection-locks', { lockKey, nodeId, version, tenantId, createdAt: new Date().toISOString() });

  // ORDER 2: PRE_WRITE audit BEFORE injection (rollback pointer)
  const auditId = `audit-${nodeId}-${version}-${Date.now()}`;
  await this.db.storeDocument('injection-audit', { auditId, nodeId, version, tenantId, phase: INJECTION_AUDIT_PHASES[0], startedAt: new Date().toISOString() });

  try {
    // ORDER 3: inject
    await this.db.storeDocument('injection-results', { nodeId, version, tenantId, code, injectedAt: new Date().toISOString() });

    // COMPLETE audit (append-only — new document, not update)
    await this.db.storeDocument('injection-audit', { auditId: `${auditId}-complete`, nodeId, version, tenantId, phase: INJECTION_AUDIT_PHASES[1], completedAt: new Date().toISOString() });
    await this.queue.enqueue('CodeInjected', { nodeId, version, tenantId, injectedAt: new Date().toISOString() });
    return DataProcessResult.success({ nodeId, version, tenantId });
  } catch (err) {
    // FAILED audit (append-only) + InjectionFailed event
    await this.db.storeDocument('injection-audit', { auditId: `${auditId}-failed`, nodeId, version, tenantId, phase: INJECTION_AUDIT_PHASES[2], failedAt: new Date().toISOString(), error: String(err) }).catch(() => {});
    await this.queue.enqueue('InjectionFailed', { nodeId, version, tenantId }).catch(() => {});
    return DataProcessResult.failure('INJECTION_FAILED', String(err));
  }
}
